      out.write("		async function loadPatchedXlsx(path){\r\n");
      out.write("			  const buf = await fetch(encodeURI(path)).then(r => r.arrayBuffer());\r\n");
      out.write("			  const zip = await JSZip.loadAsync(buf);\r\n");
      out.write("			  return await zip.generateAsync({ type: \"arraybuffer\" });\r\n");
      out.write("			}\r\n");
      out.write("\r\n");
      out.write("		document.getElementById(\"downloadStatement\").addEventListener(\"click\", async () => {\r\n");
      out.write("			  const templatePath = \"거래명세표.xlsx\";\r\n");
      out.write("			  try {\r\n");
      out.write("			    const buf = await fetch(templatePath).then(r => r.arrayBuffer());\r\n");
      out.write("			    const workbook = await XlsxPopulate.fromDataAsync(buf);\r\n");
      out.write("			    const sheet = workbook.sheet(0);\r\n");
      out.write("			    const rows = document.querySelectorAll(\"#table_body tr\");\r\n");
      out.write("			    const startRow = 8;\r\n");
      out.write("\r\n");
      out.write("			    rows.forEach((tr, i) => {\r\n");
      out.write("			    	  const r = startRow + i; // 원래대로\r\n");
      out.write("\r\n");
      out.write("			    	  const get = cls => {\r\n");
      out.write("			    	    const el = tr.querySelector(\"input.\" + cls);\r\n");
      out.write("			    	    return el?.value?.trim() || \"\";\r\n");
      out.write("			    	  };\r\n");
      out.write("\r\n");
      out.write("			    	  sheet.cell(\"B\" + r).value(get(\"medicineName\"));\r\n");
      out.write("			    	  sheet.cell(\"E\" + r).value(+get(\"inventory\") || null);\r\n");
      out.write("			    	  sheet.cell(\"F\" + r).value(+get(\"input_price\") || null);\r\n");
      out.write("			    	});\r\n");
      out.write("\r\n");
      out.write("\r\n");
      out.write("			    const blob = await workbook.outputAsync();\r\n");
      out.write("			    const url = window.URL.createObjectURL(new Blob([blob]));\r\n");
      out.write("			    const a = document.createElement(\"a\");\r\n");
      out.write("			    a.href = url;\r\n");
      out.write("			    a.download = \"거래명세표_완성본.xlsx\";\r\n");
      out.write("			    a.click();\r\n");
      out.write("			    window.URL.revokeObjectURL(url);\r\n");
      out.write("			  } catch (err) {\r\n");
      out.write("			    console.error(\"❌ 다운로드 실패\", err);\r\n");
      out.write("			    alert(\"엑셀 생성 중 오류 발생: \" + err.message);\r\n");
      out.write("			  }\r\n");
      out.write("			});\r\n");
