      out.write("		function focusRightInRow($row, $fromInput, offset = 1) {\r\n");
      out.write("			  // 보이는 td만 대상으로\r\n");
      out.write("			  const $tds = $row.children('td:visible');\r\n");
      out.write("			  const fromIdx = $fromInput.closest('td:visible').index();  // 여기서도 :visible\r\n");
      out.write("			  const targetIdx = fromIdx + offset;\r\n");
      out.write("\r\n");
      out.write("			  if (targetIdx < 0 || targetIdx >= $tds.length) return false;\r\n");
      out.write("\r\n");
      out.write("			  const $target = $tds.eq(targetIdx)\r\n");
      out.write("			    .find('input, select, textarea')\r\n");
      out.write("			    .filter(':visible:enabled')\r\n");
      out.write("			    .first();\r\n");
      out.write("\r\n");
      out.write("			  if ($target.length) {\r\n");
      out.write("			    $target.focus().select();\r\n");
      out.write("			    return true;\r\n");
      out.write("			  }\r\n");
      out.write("			  return false;\r\n");
      out.write("			}\r\n");
      out.write("\r\n");
      out.write("\r\n");
      out.write("		// .medicineName에서 Enter를 눌렀을 때 제품 검색\r\n");
      out.write("		// .medicineName 에서 Enter\r\n");
      out.write("		$(\"#wrap\").on(\"keydown\", \".medicineName\", function (e) {\r\n");
      out.write("		    if (e.key !== \"Enter\") return;\r\n");
      out.write("		    e.preventDefault();\r\n");
      out.write("		    e.stopPropagation(); \r\n");
      out.write("		    e.stopImmediatePropagation();\r\n");
      out.write("		    const $input = $(this);\r\n");
      out.write("		    const keyword = $input.val().trim();\r\n");
      out.write("		    if (keyword === \"\") return;\r\n");
      out.write("		\r\n");
      out.write("		    const $currRow = $input.closest(\"tr\");   // 현재 행\r\n");
      out.write("		    let duplicated = false;\r\n");
      out.write("		    selectedRowIndex = $(this).closest(\"tr\").index();\r\n");
      out.write("		    // 현재 행을 제외하고 중복 확인\r\n");
      out.write("		    $(\"#table_body tr\").not($currRow).each(function () {\r\n");
      out.write("		        if ($(this).find(\".medicineName\").val().trim() === keyword) {\r\n");
      out.write("		            const $inv = $(this).find(\".inventory\");\r\n");
      out.write("		            const now = parseInt($inv.val() || 0, 10);\r\n");
      out.write("		            $inv.val(now + 1);                   // 재고 +1\r\n");
      out.write("		            duplicated = true;\r\n");
      out.write("		            return false;                        // break\r\n");
      out.write("		        }\r\n");
      out.write("		    });\r\n");
      out.write("		\r\n");
      out.write("		    if (duplicated) {\r\n");
      out.write("		        calculateTotalPrice();\r\n");
      out.write("		        return;                                 // 더 할 일 없음\r\n");
      out.write("		    }\r\n");
      out.write("		    $.ajax({\r\n");
      out.write("		        url: 'updateMedicineByName.jsp',\r\n");
      out.write("		        type: 'POST',\r\n");
      out.write("		        dataType: 'json',\r\n");
      out.write("		        data: { medicineName: keyword },\r\n");
      out.write("		        success: function (res) {\r\n");
      out.write("		        	console.log(res);\r\n");
      out.write("		            if ($.isEmptyObject(res)) {          // 결과 0\r\n");
      out.write("		            	  addRow();\r\n");
      out.write("		            	  setTimeout(() => {\r\n");
      out.write("		            	    const ok = focusRightInRow($currRow, $input, 1);\r\n");
      out.write("		            	    if (!ok) {\r\n");
      out.write("		            	      const $fallback = $currRow\r\n");
      out.write("		            	        .find('input, select, textarea')\r\n");
      out.write("		            	        .filter(':visible:enabled')\r\n");
      out.write("		            	        .not($input)\r\n");
      out.write("		            	        .first();\r\n");
      out.write("		            	      if ($fallback.length) $fallback.focus();\r\n");
      out.write("		            	    }\r\n");
      out.write("		            	  }, 0);\r\n");
      out.write("		            	  return;\r\n");
      out.write("		            }\r\n");
      out.write("		            if (res.items) {                     // 규격 ≥ 2\r\n");
      out.write("		            	openPopupSelect(res.items);      // 팝업에서 선택 → fillInputs 호출\r\n");
      out.write("		                return;\r\n");
