      out.write("	// 방향키 & Enter 이동 로직 (팝업 + 입력 테이블 통합)\r\n");
      out.write("$(document).on(\"keydown\", \"input\", function (e) {\r\n");
      out.write("  const $currentInput = $(this);\r\n");
      out.write("  const $currentTd = $currentInput.closest(\"td:visible\");\r\n");
      out.write("  const $currentTr = $currentInput.closest(\"tr:visible\");\r\n");
      out.write("\r\n");
      out.write("  const $visibleTds = $currentTr.children(\"td:visible\");\r\n");
      out.write("  const visColIndex = $visibleTds.index($currentTd);\r\n");
      out.write("\r\n");
      out.write("  let $targetInput = $();\r\n");
      out.write("\r\n");
      out.write("  if(!$(\"#selTable\").is(\":visible\")){\r\n");
      out.write("	  if (e.key === \"ArrowUp\") {\r\n");
      out.write("	    const $targetTr = $currentTr.prevAll(\"tr:visible\").first();\r\n");
      out.write("	    if ($targetTr.length) {\r\n");
      out.write("	      $targetInput = $targetTr.children(\"td:visible\").eq(visColIndex)\r\n");
      out.write("	        .find(\"input:visible:enabled\").first();\r\n");
      out.write("	    }\r\n");
      out.write("	  } else if (e.key === \"ArrowDown\") {\r\n");
      out.write("	    const $tbody    = $currentTr.parent();\r\n");
      out.write("	    const $lastTr   = $tbody.children(\"tr:visible\").last();\r\n");
      out.write("	    const $targetTr = $currentTr.nextAll(\"tr:visible\").first();\r\n");
      out.write("\r\n");
      out.write("	    if ($targetTr.length) {\r\n");
      out.write("	      if ($targetTr.is($lastTr)) {\r\n");
      out.write("	        // 👉 마지막 행이면 .medicineName으로 이동\r\n");
      out.write("	        $targetInput = $targetTr.find(\"input.medicineName:visible:enabled\").first();\r\n");
      out.write("	      } else {\r\n");
      out.write("	        $targetInput = $targetTr.children(\"td:visible\").eq(visColIndex)\r\n");
      out.write("	          .find(\"input:visible:enabled\").first();\r\n");
      out.write("	      }\r\n");
      out.write("	    }\r\n");
      out.write("	  } else if (e.key === \"ArrowLeft\") {\r\n");
      out.write("	    const el = $currentInput.get(0);\r\n");
      out.write("	    if (el.selectionStart === 0 && visColIndex > 0) {\r\n");
      out.write("	      $targetInput = $visibleTds.eq(visColIndex - 1)\r\n");
      out.write("	        .find(\"input:visible:enabled\").first();\r\n");
      out.write("	    }\r\n");
      out.write("	  } else if (e.key === \"ArrowRight\") {\r\n");
      out.write("	    const el = $currentInput.get(0);\r\n");
      out.write("	    if (el.selectionEnd === el.value.length && visColIndex < $visibleTds.length - 1) {\r\n");
      out.write("	      $targetInput = $visibleTds.eq(visColIndex + 1)\r\n");
      out.write("	        .find(\"input:visible:enabled\").first();\r\n");
      out.write("	    }\r\n");
      out.write("	  } else if (e.key === \"Enter\") {\r\n");
      out.write("	    const $targetTr = $currentTr.nextAll(\"tr:visible\").first();\r\n");
      out.write("	    if ($targetTr.length) {\r\n");
      out.write("	      $targetInput = $targetTr.children(\"td:visible\").eq(visColIndex)\r\n");
      out.write("	        .find(\"input:visible:enabled\").first();\r\n");
      out.write("	    }\r\n");
      out.write("	  } else {\r\n");
      out.write("	    return;\r\n");
      out.write("	  }\r\n");
      out.write("	}\r\n");
      out.write("\r\n");
      out.write("	  \r\n");
      out.write("\r\n");
      out.write("  if ($targetInput.length) {\r\n");
      out.write("    e.preventDefault();\r\n");
      out.write("    $(\"input\").removeClass(\"inputCheckStyle\");\r\n");
      out.write("    $targetInput.addClass(\"inputCheckStyle\").focus().select();\r\n");
      out.write("  }\r\n");
      out.write("});\r\n");
      out.write("\r\n");
      out.write("	\r\n");
      out.write("	$(document).on('keydown', function(event) {\r\n");
      out.write("\r\n");
      out.write("		if ((event.ctrlKey && (event.key === 's' || event.key === 'S')) || event.keyCode == 122) {\r\n");
      out.write("	        event.preventDefault();\r\n");
      out.write("	        $(\"#exhaustionInv\").click(); // #exhaustionInv 버튼의 클릭 이벤트 트리거\r\n");
      out.write("	    }\r\n");
      out.write("	    if(event.keyCode == 122){\r\n");
      out.write("	        event.preventDefault();\r\n");
      out.write("	        $(\"#exhaustionInv\").click();\r\n");
      out.write("	    }\r\n");
      out.write("		if(event.keyCode == 118){\r\n");
      out.write("	        event.preventDefault();\r\n");
      out.write("	        window.location.href=\"inventory_Exhaustion.jsp\";\r\n");
      out.write("	    }\r\n");
      out.write("		if(event.keyCode == 116){\r\n");
      out.write("	        event.preventDefault();\r\n");
      out.write("	    }\r\n");
      out.write("	    if (event.keyCode === 32) {\r\n");
      out.write("\r\n");
