      out.write("	        return false;\r\n");
      out.write("	    }\r\n");
      out.write("	    var row = $(button).closest(\"tr\");\r\n");
      out.write("	    if (row.is(':last-child')) {\r\n");
      out.write("	        return false;\r\n");
      out.write("	    }\r\n");
      out.write("	    var price = parseFloat(row.find(\"#price\").val());\r\n");
      out.write("	    let inventory = parseFloat(row.find(\".inventory\").val());\r\n");
      out.write("	    var totalPrice = parseFloat($(\"#totalPrice\").text());\r\n");
      out.write("	    var generalPrice = parseFloat($(\"#generalPrice\").val());\r\n");
      out.write("\r\n");
