      out.write("	    totalPrice -= price * inventory;\r\n");
      out.write("	    generalPrice -= price * inventory;\r\n");
      out.write("\r\n");
      out.write("	    // 행을 제거\r\n");
      out.write("	    row.remove();\r\n");
